    .lv-dropdown { position: relative; display: inline-block; }
    .lv-dropdown__trigger {
      display: inline-flex;
      align-items: center;
      gap: var(--lv-space-1);
      font-family: var(--lv-font-sans);
      font-size: var(--lv-text-sm);
