    if (item.disabled) return;
    this.dispatchEvent(
      new CustomEvent("lv-select", { detail: item.key, bubbles: true, composed: true })
    );
    this.closeMenu();
    this.focusTrigger();
  }

  private onTriggerKeyDown(e: KeyboardEvent) {
    if (this.disabled) return;
    switch (e.key) {
      case "ArrowDown":
      case "Enter":
      case " ":
        e.preventDefault();
        this.openMenu();
        break;
      case "ArrowUp":
        e.preventDefault();
        this.openMenu();
        break;
    }
  }

  private onMenuKeyDown(e: KeyboardEvent) {
    switch (e.key) {
      case "ArrowDown":
        e.preventDefault();
        this.moveActive(1);
        this.focusItem(this.activeIndex);
        break;
      case "ArrowUp":
