  private onDragLeave() {
    this.dragOver = false;
  }

  private onDrop(e: DragEvent) {
    if (this.disabled) return;
    e.preventDefault();
    this.dragOver = false;
    const files = e.dataTransfer?.files;
    if (files && files.length > 0) this.addFiles(files);
