      display: inline-flex;
      align-items: center;
      gap: var(--lv-space-2);
      background: transparent;
      border: 0;
      padding: 0;
      cursor: pointer;
      font-family: var(--lv-font-sans);
      font-size: var(--lv-text-sm);
      color: var(--lv-color-fg);
      text-align: left;
