        break;
      case "End":
        if (this.open) {
          e.preventDefault();
          this.activeIndex = this.options.length - 1;
        }
        break;
    }
  }

  private onListKeyDown(e: KeyboardEvent) {
    switch (e.key) {
      case "ArrowDown":
