  render() {
    const selected = this.selectedLabel();
    return html`
      <div class="lv-select">
        <button
          class="lv-select__trigger ${this.invalid ? "lv-select__trigger--invalid" : ""}"
          id=${this.inputId || ""}
          type="button"
          role="combobox"
          aria-expanded=${this.open ? "true" : "false"}
