/**
 * Tab definition for `<lv-tabs>`.
 */
export interface TabItem {
  /** Unique identifier for this tab; used as the `value` of the active tab. */
  id: string;
  /** Visible tab label. */
  label: string;
  /** Disables the tab. */
  disabled?: boolean;
}

